function.body:
TYPE RECORD IS REF CURSOR;
  cur_parameter RECORD;
  cur_amortline RECORD;


  v_record_id VARCHAR2(32) ;

  v_resultstr VARCHAR2(2000) := '';  
  v_Message VARCHAR2(2000) := '';  
  v_result NUMBER:=1;

BEGIN
  --  Update AD_PInstance
  DBMS_OUTPUT.PUT_LINE('Updating PInstance - Processing ' || pinstance_id) ;
  v_resultstr := 'PInstanceNotFound';
  AD_UPDATE_PINSTANCE(NULL, NULL, 'Y', NULL, NULL) ;

  BEGIN --BODY

    -- Get Parameters
    v_resultstr := 'ReadingParameters';

    FOR cur_parameter IN
      (SELECT i.record_id, i.ad_user_id, p.parametername, p.p_string,
        p.p_number, p.p_date, p.ad_org_id, p.ad_client_id
      FROM ad_pinstance i
      LEFT JOIN ad_pinstance_para p
        ON i.ad_pinstance_id=p.ad_pinstance_id
      WHERE i.ad_pinstance_id=pinstance_id
      ORDER BY p.seqno
      )
    LOOP
      v_record_id:=cur_parameter.record_id;

    END LOOP; -- Get Parameter    	  


    DBMS_OUTPUT.PUT_LINE('  Record_ID=' || v_record_id);
    -- Check that we have some restrictions
    v_resultstr := 'CheckRestriction';

     FOR cur_amortline IN
      (
        SELECT 	
        date_trunc('month', EM_Ssast_Datecancelled + interval '1 month') as fecha_baja_begin,
        a.EM_Ssast_Datecancelled,
        al.A_Amortizationline_Id, 
        enddate
        from A_Amortizationline al
        left join a_asset a on a.A_Asset_ID = al.A_Asset_ID
        left join A_Amortization am on am.A_Amortization_id = al.A_Amortization_id
        WHERE a.a_asset_id = v_record_id
        AND enddate >= date_trunc('month', EM_Ssast_Datecancelled + interval '1 month')
      )
    LOOP
        -- Desvincular linea de amortizacion en el Activo
        UPDATE A_Amortizationline SET a_asset_id = null
        where A_Amortizationline_id = cur_amortline.A_Amortizationline_Id ;

    END LOOP; -- Get Parameter    	 


  --<<FINISH_PROCESS>>
  --  Update AD_PInstance
  DBMS_OUTPUT.PUT_LINE('Updating PInstance - Finished ' || v_message);
 AD_UPDATE_PINSTANCE(pinstance_id, NULL, 'N', 1, NULL) ;	
  END; --BODY
EXCEPTION
  WHEN OTHERS THEN
    v_resultstr:= '@ERROR=' || SQLERRM;
    DBMS_OUTPUT.PUT_LINE(v_resultstr);
    AD_UPDATE_PINSTANCE(pinstance_id, NULL, 'N', 0, v_resultstr);
-- Commented by jaulestia RETURN;
END SDA_DERECOGNITION_ASSET
